sql:
SELECT (
    SELECT COUNT(*)
    FROM models
    WHERE mse > (SELECT AVG(mse) FROM models)
) * 100.0 / (
    SELECT COUNT(*)
    FROM models
) AS percentage_higher_mse;

SELECT model_name, rmse
FROM models
WHERE rmse = (SELECT MAX(rmse) FROM models);

SELECT selected_by, AVG(importance_score) as Average_Importance_Score
FROM model_variables
GROUP BY selected_by;

SELECT model_id
FROM models
WHERE model_type = 'Regression' AND trained_by = 1;

SELECT (COUNT(*) * 100.0 / (SELECT COUNT(*) FROM models)) as percentage
FROM models
WHERE aic > 2100;

SELECT model_id, model_name, aic
FROM models
WHERE aic = (SELECT MIN(aic) FROM models) OR aic = (SELECT MAX(aic) FROM models);
